function DiscordTab({ config, saveConfig, vehicles }) {
  const [form, setForm] = useState({
    discordWebhookGeneral: config.discordWebhookGeneral || '',
    discordWebhookMaintenance: config.discordWebhookMaintenance || '',
    discordWebhookByVehicle: config.discordWebhookByVehicle || {},
    discordWebhookMaintByVehicle: config.discordWebhookMaintByVehicle || {},
  });

  // Sincronizar form cuando el config cambia (ej: carga desde storage)
  useEffect(() => {
    setForm({
      discordWebhookGeneral: config.discordWebhookGeneral || '',
      discordWebhookMaintenance: config.discordWebhookMaintenance || '',
      discordWebhookByVehicle: config.discordWebhookByVehicle || {},
      discordWebhookMaintByVehicle: config.discordWebhookMaintByVehicle || {},
    });
  }, [config.discordWebhookMaintByVehicle, config.discordWebhookByVehicle, config.discordWebhookGeneral, config.discordWebhookMaintenance]);
  // testStatus: { key: 'idle' | 'sending' | 'success' | 'error', error: string }
  const [testStatus, setTestStatus] = useState({});

  const setStatus = (key, status, error = '') => setTestStatus(s => ({ ...s, [key]: { status, error } }));

  const testWebhook = async (url, label, key) => {
    if (!url || !url.trim()) { setStatus(key, 'error', 'Pega el webhook primero'); return; }
    setStatus(key, 'sending');
    const result = await sendDiscordNotification(url, {
      title: `🧪 PRUEBA · ${label}`,
      description: 'Si ves este mensaje en Discord, ¡la integración funciona! 🎉',
      color: 0x10b981,
      footer: { text: `Transporte Emporium · ${new Date().toLocaleString('es-VE')}` },
    });
    if (result.ok) setStatus(key, 'success');
    else setStatus(key, 'error', result.error);
  };

  const guardar = () => {
    saveConfig({ ...config, ...form });
    setStatus('save', 'success');
    setTimeout(() => setStatus('save', 'idle'), 3000);
  };

  // Componente de botón con feedback
  const TestBtn = ({ webhookKey, url, label }) => {
    const st = testStatus[webhookKey] || { status: 'idle' };
    let bg = 'bg-indigo-100 text-indigo-700 border-indigo-300 hover:bg-indigo-200';
    let icon = <Send className="w-3 h-3" />;
    let text = '';
    if (st.status === 'sending') { bg = 'bg-amber-100 text-amber-700 border-amber-300'; text = 'Enviando...'; }
    else if (st.status === 'success') { bg = 'bg-emerald-100 text-emerald-700 border-emerald-300'; icon = <CheckCircle2 className="w-3 h-3" />; text = '¡Llegó!'; }
    else if (st.status === 'error') { bg = 'bg-rose-100 text-rose-700 border-rose-300'; icon = <X className="w-3 h-3" />; text = 'Error'; }
    return (
      <div className="flex flex-col items-end gap-1">
        <button onClick={() => testWebhook(url, label, webhookKey)}
          className={`text-xs px-3 py-2 rounded border font-bold flex items-center gap-1 ${bg} transition`}>
          {icon} {text || 'Probar'}
        </button>
        {st.status === 'error' && st.error && (
          <div className="text-[10px] text-rose-700 text-right max-w-[180px] break-words">{st.error}</div>
        )}
      </div>
    );
  };

  return (
    <div className="space-y-4 max-w-3xl">
      <div>
        <h2 className="text-xl font-black text-stone-900 flex items-center gap-2">
          <MessageCircle className="w-5 h-5 text-indigo-600" /> Integración Discord
        </h2>
        <p className="text-sm text-stone-600">Notificaciones automáticas a tus canales del servidor "Transporte Emporium"</p>
      </div>

      {/* Cómo funciona */}
      <div className="bg-indigo-50 border border-indigo-200 rounded-xl p-4">
        <h3 className="font-bold text-indigo-900 text-sm mb-2">📌 Lógica de envío automático según tu servidor</h3>
        <div className="text-xs text-indigo-800 space-y-1.5">
          <div>🚛 <b>Viajes</b> (inicio + llegada) → <b>canal de la unidad</b> (ej: NPR 01 → <code className="bg-indigo-100 px-1 rounded">#npr-01-daniel</code>)</div>
          <div>📸 <b>Fotos de Transferencia y Daño</b> → <b>canal general de transporte</b></div>
          <div>🔧 <b>Fotos de Combustible y Mantenimiento</b> → <b>canal de mantenimiento</b></div>
        </div>
      </div>

      {/* Guía */}
      <div className="bg-stone-50 border border-stone-200 rounded-xl p-4">
        <h3 className="font-bold text-stone-900 text-sm mb-2">📚 Cómo crear un Webhook en Discord</h3>
        <ol className="text-xs text-stone-700 space-y-1 list-decimal list-inside">
          <li>En Discord, ve al canal donde quieres las notificaciones</li>
          <li>Click en el <b>⚙️ engranaje</b> (Editar canal) al lado del nombre del canal</li>
          <li>Click en <b>Integraciones → Webhooks → Nuevo webhook</b></li>
          <li>Dale un nombre (ej: "Bot Emporium") y click <b>Copiar URL del webhook</b></li>
          <li>Pégala en el campo correspondiente abajo y click en <b>Probar</b></li>
        </ol>
      </div>

      {/* Webhook general (transporte general) */}
      <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-1">📢 Canal general de transporte</h3>
        <p className="text-xs text-stone-600 mb-3">Para fotos del día (transferencias, daños) y notificaciones generales. Ej: <code className="bg-stone-100 px-1 rounded">#grupo-transporte-en-general</code></p>
        <div className="flex items-end gap-2">
          <div className="flex-1">
            <input type="text" value={form.discordWebhookGeneral} onChange={e => { setForm({ ...form, discordWebhookGeneral: e.target.value }); setStatus('general', 'idle'); }}
              placeholder="https://discord.com/api/webhooks/..." className="dark-input font-mono text-xs" />
          </div>
          <TestBtn webhookKey="general" url={form.discordWebhookGeneral} label="GENERAL" />
        </div>
      </div>

      {/* Webhook mantenimiento */}
      <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-1">🔧 Canal de mantenimiento</h3>
        <p className="text-xs text-stone-600 mb-3">Para chequeos diarios, fotos de combustible y mantenimiento. Ej: <code className="bg-stone-100 px-1 rounded">#info-servicio-Mantenimiento</code></p>
        <div className="flex items-end gap-2">
          <div className="flex-1">
            <input type="text" value={form.discordWebhookMaintenance} onChange={e => { setForm({ ...form, discordWebhookMaintenance: e.target.value }); setStatus('maint', 'idle'); }}
              placeholder="https://discord.com/api/webhooks/..." className="dark-input font-mono text-xs" />
          </div>
          <TestBtn webhookKey="maint" url={form.discordWebhookMaintenance} label="MANTENIMIENTO" />
        </div>
      </div>

      {/* Webhooks por unidad */}
      <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-1">🚛 Canales por unidad — <span className="text-emerald-700">Viajes</span></h3>
        <p className="text-xs text-stone-600 mb-4">Inicio y fin de viajes. Ej: NPR 01 → <code className="bg-stone-100 px-1 rounded">#npr-01-daniel</code></p>
        <div className="space-y-3">
          {vehicles.map(v => (
            <div key={v.id} className="flex items-end gap-2">
              <div className="flex-1">
                <DarkField label={`${v.code} (${v.plate})`}>
                  <input type="text" value={form.discordWebhookByVehicle[v.id] || ''}
                    onChange={e => { setForm({ ...form, discordWebhookByVehicle: { ...form.discordWebhookByVehicle, [v.id]: e.target.value } }); setStatus(v.id, 'idle'); }}
                    placeholder="https://discord.com/api/webhooks/..." className="dark-input font-mono text-xs" />
                </DarkField>
              </div>
              <TestBtn webhookKey={v.id} url={form.discordWebhookByVehicle[v.id]} label={v.code} />
            </div>
          ))}
        </div>
      </div>

      {/* Webhooks mantenimiento — ahora en Flota */}
      <div className="bg-indigo-50 rounded-2xl p-5 border border-indigo-200">
        <h3 className="font-bold text-indigo-900 mb-1">🔧 Canales por unidad — Mantenimiento</h3>
        <p className="text-xs text-indigo-700">Los webhooks de mantenimiento ahora se configuran directamente en cada camión.</p>
        <p className="text-xs text-indigo-600 mt-1">Ve a <b>Flota → ✏️ editar camión → Webhook Discord Mantenimiento</b></p>
      </div>

      {/* Guardar */}
      <div className="sticky bottom-4">
        <button onClick={guardar}
          className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-xl transition">
          <Save className="w-5 h-5" /> {testStatus.save?.status === 'success' ? '✅ Guardado correctamente' : 'Guardar configuración'}
        </button>
      </div>

      {/* Troubleshooting */}
      <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 text-sm">
        <div className="font-bold text-amber-900 mb-2">⚠️ Si "Probar" da error</div>
        <ul className="text-xs text-amber-800 space-y-1 list-disc list-inside">
          <li>Asegúrate que la URL completa esté pegada (puede cortarse al copiar)</li>
          <li>Verifica que el webhook no haya sido borrado en Discord</li>
          <li>Si usas adblocker, desactívalo temporalmente</li>
          <li>Algunos navegadores con configuración estricta bloquean las peticiones — prueba en Chrome estándar</li>
        </ul>
      </div>
    </div>
  );
}

function SettingsTab({ config, saveConfig, saveTrips, saveActiveTrips, savePhotos, saveGpsTracks, saveArchived, vehicles, saveVehicles }) {
  const [fuelPrice, setFuelPrice] = useState(config.fuelPrice || 0.5);
  const [availableVoices, setAvailableVoices] = useState([]);
  const [selectedVoice, setSelectedVoice] = useState(localStorage.getItem('emp:voice_name') || '');
  const [voiceMuted, setVoiceMuted] = useState(localStorage.getItem('emp:voice_muted') !== 'false');

  // Cargar voces disponibles
  useEffect(() => {
    const loadVoices = () => {
      const voices = getSpanishVoices();
      setAvailableVoices(voices);
    };
    loadVoices();
    if ('speechSynthesis' in window) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const testVoice = (voiceName) => {
    // Temporalmente quitar mute si está muteado para esta prueba
    const wasMuted = localStorage.getItem('emp:voice_muted') !== 'false';
    localStorage.setItem('emp:voice_muted', 'false');
    if (voiceName) localStorage.setItem('emp:voice_name', voiceName);
    speakText(`Hola José, así sonará la voz seleccionada. ${getGreetingByTime()}, bienvenido al Sistema Emporium.`);
    setTimeout(() => {
      if (wasMuted) localStorage.setItem('emp:voice_muted', 'true');
    }, 5000);
  };

  const handleSelectVoice = (voiceName) => {
    setSelectedVoice(voiceName);
    localStorage.setItem('emp:voice_name', voiceName);
  };

  const toggleVoiceMute = () => {
    const newMuted = !voiceMuted;
    setVoiceMuted(newMuted);
    localStorage.setItem('emp:voice_muted', newMuted ? 'true' : 'false');
  };

  const limpiarViajesPrueba = () => {
    if (!confirm('¿Borrar TODOS los viajes, fotos y recorridos GPS?\n\nEsto deja la app limpia para empezar de cero.\nLos vehículos, choferes y sucursales se mantienen.')) return;
    if (!confirm('Confirma una segunda vez: ¿Estás seguro?')) return;
    saveTrips([]);
    saveActiveTrips([]);
    savePhotos([]);
    saveGpsTracks([]);
    saveArchived([]);
    // Resetear estado de vehículos
    saveVehicles(vehicles.map(v => ({ ...v, status: v.status === 'EN TALLER' ? 'EN TALLER' : 'AL DIA' })));
    alert('✅ App limpia. Puedes empezar a registrar viajes reales.');
  };

  const cancelarViajesActivos = async () => {
    if (!confirm(`¿Cancelar los ${vehicles.filter(v=>v.status==='EN RUTA').length || 'todos los'} viajes activos?\n\nLos camiones quedarán disponibles para nuevos viajes.`)) return;
    try { const { supabase } = await import('./lib/syncStorage.js'); await supabase.from('app_data').delete().eq('key', 'emp:v4:active_trips'); } catch(e) {}
    saveActiveTrips([]);
    saveVehicles(vehicles.map(v => v.status === 'EN RUTA' ? { ...v, status: 'AL DIA' } : v));
    alert('✅ Viajes activos cancelados.');
  };

  const reiniciarKmVehiculos = () => {
    const km = prompt('Reiniciar el KM actual de cada vehículo a:\n(deja vacío para mantener los actuales)');
    if (km === null || km === '') return;
    const num = Number(km);
    if (isNaN(num)) return alert('Número inválido');
    saveVehicles(vehicles.map(v => ({ ...v, currentKm: num })));
    alert('✅ KM actualizado');
  };

  return (
    <div className="space-y-4 max-w-2xl">
      <div>
        <h2 className="text-xl font-black text-stone-900">Configuración</h2>
        <p className="text-sm text-stone-600">Ajustes generales y mantenimiento de datos</p>
      </div>

      {/* Configuración general */}
      <div className="bg-white rounded-2xl border border-stone-200 p-5 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-3 flex items-center gap-2">
          <Settings className="w-4 h-4 text-emerald-700" /> Ajustes generales
        </h3>
        <DarkField label="Precio del combustible (USD por litro)">
          <input type="number" step="0.01" value={fuelPrice} onChange={e => setFuelPrice(Number(e.target.value))} className="dark-input" />
        </DarkField>
        <button onClick={() => { saveConfig({ ...config, fuelPrice }); alert('✅ Guardado'); }}
          className="w-full mt-3 bg-emerald-600 hover:bg-emerald-700 text-white py-2.5 rounded-lg font-bold transition">
          Guardar cambios
        </button>
      </div>

      {/* Sistema de voz */}
      <div className="bg-white rounded-2xl border border-stone-200 p-5 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-3 flex items-center gap-2">
          🔊 Sistema de voz
        </h3>
        <p className="text-xs text-stone-600 mb-3">
          La app puede hablar para dar saludos, recordatorios de seguridad y alertas de velocidad. Por defecto está <b>silenciada</b>.
        </p>

        <div className="flex items-center gap-2 mb-4">
          <button onClick={toggleVoiceMute}
            className={`px-4 py-2.5 rounded-lg font-bold flex items-center gap-2 ${
              voiceMuted
                ? 'bg-stone-200 text-stone-700 hover:bg-stone-300'
                : 'bg-emerald-600 text-white hover:bg-emerald-700'
            }`}>
            {voiceMuted ? '🔇 Voz silenciada' : '🔊 Voz activada'}
          </button>
          <span className="text-xs text-stone-500">Click para alternar</span>
        </div>

        {availableVoices.length === 0 ? (
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 text-xs text-amber-900">
            ⚠️ No hay voces en español disponibles en este dispositivo. Prueba en otro navegador (Chrome funciona mejor).
          </div>
        ) : (
          <div>
            <div className="text-xs font-bold text-stone-700 mb-2 uppercase tracking-wider">
              Voces disponibles ({availableVoices.length})
            </div>
            <div className="space-y-1.5 max-h-60 overflow-y-auto">
              {availableVoices.map(v => (
                <div key={v.name} className={`flex items-center gap-2 p-2 rounded-lg border ${
                  selectedVoice === v.name ? 'bg-emerald-50 border-emerald-300' : 'bg-stone-50 border-stone-200'
                }`}>
                  <button onClick={() => testVoice(v.name)}
                    className="bg-emerald-600 hover:bg-emerald-700 text-white px-3 py-1.5 rounded text-xs font-bold flex items-center gap-1 shrink-0">
                    ▶ Probar
                  </button>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-bold text-stone-900 truncate">{v.name}</div>
                    <div className="text-[10px] text-stone-500 font-mono">{v.lang}</div>
                  </div>
                  <button onClick={() => handleSelectVoice(v.name)}
                    className={`px-3 py-1.5 rounded text-xs font-bold ${
                      selectedVoice === v.name
                        ? 'bg-emerald-700 text-white'
                        : 'bg-stone-200 text-stone-700 hover:bg-stone-300'
                    }`}>
                    {selectedVoice === v.name ? '✓ Elegida' : 'Elegir'}
                  </button>
                </div>
              ))}
            </div>
            <div className="mt-3 text-xs text-stone-500 bg-blue-50 border border-blue-200 rounded p-2">
              💡 Prueba varias voces y elige la que más te guste. Tu elección se guarda automáticamente.
            </div>
          </div>
        )}
      </div>

      {/* Mantenimiento de datos */}
      <div className="bg-white rounded-2xl border border-stone-200 p-5 shadow-sm">
        <h3 className="font-bold text-stone-900 mb-1 flex items-center gap-2">
          <Trash2 className="w-4 h-4 text-rose-600" /> Mantenimiento de datos
        </h3>
        <p className="text-xs text-stone-600 mb-4">Útil cuando termines de probar y quieras empezar limpio</p>

        <div className="space-y-3">
          <div className="border border-amber-200 bg-amber-50 rounded-xl p-3">
            <div className="font-semibold text-amber-900 text-sm mb-1">🔄 Reiniciar KM de vehículos</div>
            <div className="text-xs text-amber-800 mb-2">Para corregir el KM actual de todos los camiones de una vez</div>
            <button onClick={reiniciarKmVehiculos} className="bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg text-sm font-bold">
              Reiniciar KM
            </button>
          </div>

          <div className="border-2 border-amber-200 bg-amber-50 rounded-xl p-3">
            <div className="font-semibold text-amber-900 text-sm mb-1">🚛 Cancelar viajes activos</div>
            <div className="text-xs text-amber-800 mb-2">
              Cancela todos los viajes que quedaron abiertos sin completar.<br/>
              Los camiones quedan disponibles para nuevos viajes.
            </div>
            <button onClick={cancelarViajesActivos} className="bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg text-sm font-bold">
              Cancelar viajes activos
            </button>
          </div>

          <div className="border-2 border-rose-200 bg-rose-50 rounded-xl p-3">
            <div className="font-semibold text-rose-900 text-sm mb-1">🗑️ Limpiar viajes de prueba</div>
            <div className="text-xs text-rose-800 mb-2">
              Borra todos los viajes, fotos, recorridos GPS y meses archivados.<br/>
              <b>Mantiene</b> vehículos, choferes, sucursales y configuración.
            </div>
            <button onClick={limpiarViajesPrueba} className="bg-rose-600 hover:bg-rose-700 text-white px-4 py-2 rounded-lg text-sm font-bold">
              Limpiar todo
            </button>
          </div>
        </div>
      </div>

      {/* Info sobre PINs */}
      <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm">
        <h3 className="font-bold text-blue-900 mb-2">🔐 PINs de acceso</h3>
        <div className="text-xs text-blue-800 space-y-1">
          <div>• <b>Coordinador (José):</b> 0000</div>
          <div>• <b>Choferes:</b> Cada uno tiene su PIN (editable en pestaña "Choferes")</div>
          <div className="text-blue-600 italic mt-2">Recuerda cambiar los PINs cuando estés en producción</div>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// CHECKLIST PRE-VIAJE — PUERTA DE ENTRADA
// Verifica si el vehículo ya fue chequeado hoy.
// Si no → muestra el formulario completo (obligatorio).
// Si sí → muestra quién lo chequeó y permite continuar.
// ============================================================
// ============================================================
// FORMULARIO CIERRE DE JORNADA
// ============================================================
function EndShiftForm({ driver, vehicle, trips = [], kmInicial = '', onConfirm, onBack }) {
  const [kmFinal, setKmFinal] = useState(kmInicial ? String(kmInicial) : '');
  const [foto, setFoto] = useState(null);
  const [fotoChofer, setFotoChofer] = useState(null);
  const [novedades, setNovedades] = useState('');
  const [combustibleRestante, setCombustibleRestante] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [simpleItems, setSimpleItems] = useState({ estacionado: false, luces: false, puertas: false });
  const [cauchos, setCauchos] = useState('');
  const [cauchoNota, setCauchoNota] = useState('');
  const [danos, setDanos] = useState('');
  const [danosNota, setDanosNota] = useState('');
  const hora = new Date().toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit'});
  const totalKm = trips.reduce((s,t)=>s+(Number(t.kmTraveled)||0),0);
  const handleFoto = (e) => { const file = e.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = ev => setFoto(ev.target.result); reader.readAsDataURL(file); };
  const handleFotoChofer = (e) => { const file = e.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = ev => setFotoChofer(ev.target.result); reader.readAsDataURL(file); };
  const allSimpleChecked = Object.values(simpleItems).every(Boolean);
  const cauchoNecesitaNota = (cauchos === 'revisar' || cauchos === 'mal') && !cauchoNota.trim();
  const danosNecesitaNota = (danos === 'menor' || danos === 'grave') && !danosNota.trim();
  const kmValido = kmFinal !== '' && Number(kmFinal) > 0;
  const canSubmit = kmValido && foto && fotoChofer && allSimpleChecked && cauchos && danos && !cauchoNecesitaNota && !danosNecesitaNota;
  const submit = async () => {
    if (!canSubmit) return;
    if (vehicle?.currentKm && Number(kmFinal) < vehicle.currentKm) {
      if (!confirm(`⚠️ KM ingresado (${Number(kmFinal).toLocaleString()}) menor al actual (${vehicle.currentKm.toLocaleString()}). ¿Continuar?`)) return;
    }
    setSubmitting(true);
    const hayAlerta = cauchos !== 'bien' || danos !== 'ninguno';
    await onConfirm({ kmFinal: Number(kmFinal), foto, fotoChofer, items: { ...simpleItems, cauchos, danos }, novedades, combustibleRestante: combustibleRestante || '', hayAlerta, cauchoNota, danosNota });
    setSubmitting(false);
  };
  const BtnOpt = ({ active, color, onClick, children }) => {
    const colors = { green: active ? 'bg-emerald-50 border-emerald-400 text-emerald-800' : 'bg-stone-50 border-stone-200 text-stone-500', amber: active ? 'bg-amber-50 border-amber-400 text-amber-800' : 'bg-stone-50 border-stone-200 text-stone-500', red: active ? 'bg-red-50 border-red-400 text-red-800' : 'bg-stone-50 border-stone-200 text-stone-500' };
    return <button onClick={onClick} className={`flex-1 py-2 px-2 rounded-xl border-2 text-xs font-bold text-center transition ${colors[color]}`}>{children}</button>;
  };
  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 to-stone-900 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm overflow-hidden">
        <div className="bg-indigo-700 px-5 py-4 text-white">
          <div className="text-xs font-mono uppercase tracking-wider opacity-80 mb-1">🌙 Cierre de jornada</div>
          <div className="font-black text-lg">{driver.name}</div>
          <div className="text-indigo-200 text-sm">{hora} · {vehicle?.code || '—'} · {trips.length} viajes · {totalKm} km</div>
        </div>
        <div className="px-5 pt-4 pb-2 space-y-4 max-h-[75vh] overflow-y-auto">
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-1">🔢 KM Final del odómetro <span className="text-red-500">*</span></label>
            {vehicle?.lastParkedKm && <div className="text-xs text-stone-400 mb-1">Último: {vehicle.lastParkedKm.toLocaleString()} km</div>}
            <input type="number" value={kmFinal} onChange={e=>setKmFinal(e.target.value)} placeholder="Ingresa el KM del odómetro" className="w-full border-2 border-stone-200 rounded-xl px-3 py-2 text-sm font-mono focus:border-indigo-400 outline-none" />
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">⛽ Combustible restante</label>
            <div className="flex gap-2">
              {['1/4','1/2','3/4','Full'].map(opt => (
                <button key={opt} onClick={()=>setCombustibleRestante(opt)}
                  className={`flex-1 py-2 rounded-xl border-2 text-sm font-bold transition ${combustibleRestante===opt ? 'bg-emerald-50 border-emerald-400 text-emerald-800' : 'bg-stone-50 border-stone-200 text-stone-500'}`}>
                  {opt}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">✅ Chequeo rápido <span className="text-red-500">*</span></label>
            <div className="space-y-2">
              {[{key:'estacionado',label:'🅿️ Estacionado en su sitio'},{key:'luces',label:'💡 Luces apagadas'},{key:'puertas',label:'🔒 Puertas cerradas y aseguradas'}].map(item => (
                <button key={item.key} onClick={() => setSimpleItems(p=>({...p,[item.key]:!p[item.key]}))}
                  className={`w-full flex items-center gap-3 p-2.5 rounded-xl border-2 text-sm text-left transition ${simpleItems[item.key] ? 'bg-emerald-50 border-emerald-300 text-emerald-800' : 'bg-stone-50 border-stone-200 text-stone-600'}`}>
                  <div className={`w-5 h-5 rounded-full border-2 flex-shrink-0 flex items-center justify-center ${simpleItems[item.key] ? 'bg-emerald-500 border-emerald-500' : 'border-stone-300'}`}>{simpleItems[item.key] && <span className="text-white text-xs">✓</span>}</div>
                  {item.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">🔵 Estado de cauchos <span className="text-red-500">*</span></label>
            <div className="flex gap-2">
              <BtnOpt active={cauchos==='bien'} color="green" onClick={()=>{setCauchos('bien');setCauchoNota('');}}>✅ Bien</BtnOpt>
              <BtnOpt active={cauchos==='revisar'} color="amber" onClick={()=>setCauchos('revisar')}>⚠️ Revisar</BtnOpt>
              <BtnOpt active={cauchos==='mal'} color="red" onClick={()=>setCauchos('mal')}>🔴 Mal estado</BtnOpt>
            </div>
            {(cauchos==='revisar'||cauchos==='mal') && (
              <input value={cauchoNota} onChange={e=>setCauchoNota(e.target.value)} placeholder="Describe el problema (obligatorio)..."
                className={`w-full mt-2 border-2 rounded-xl px-3 py-2 text-sm focus:outline-none ${!cauchoNota.trim() ? 'border-red-300' : 'border-amber-300'}`} />
            )}
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">🔍 Daños visibles <span className="text-red-500">*</span></label>
            <div className="flex gap-2">
              <BtnOpt active={danos==='ninguno'} color="green" onClick={()=>{setDanos('ninguno');setDanosNota('');}}>✅ Ninguno</BtnOpt>
              <BtnOpt active={danos==='menor'} color="amber" onClick={()=>setDanos('menor')}>⚠️ Menor</BtnOpt>
              <BtnOpt active={danos==='grave'} color="red" onClick={()=>setDanos('grave')}>🔴 Grave</BtnOpt>
            </div>
            {(danos==='menor'||danos==='grave') && (
              <input value={danosNota} onChange={e=>setDanosNota(e.target.value)} placeholder="Describe el daño (obligatorio)..."
                className={`w-full mt-2 border-2 rounded-xl px-3 py-2 text-sm focus:outline-none ${!danosNota.trim() ? 'border-red-300' : 'border-amber-300'}`} />
            )}
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">🤳 Selfie del chofer <span className="text-red-500">*</span></label>
            {fotoChofer ? (
              <div className="relative"><img src={fotoChofer} alt="Chofer" className="w-full h-32 object-cover rounded-xl border-2 border-indigo-300" /><button onClick={() => setFotoChofer(null)} className="absolute top-1 right-1 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs">✕</button></div>
            ) : (
              <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-indigo-300 rounded-xl cursor-pointer hover:bg-indigo-50">
                <span className="text-2xl">🤳</span><span className="text-xs text-indigo-400 mt-1">Selfie (cámara frontal)</span>
                <input type="file" accept="image/*" capture="user" className="hidden" onChange={handleFotoChofer} />
              </label>
            )}
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">📸 Foto del camión guardado <span className="text-red-500">*</span></label>
            {foto ? (
              <div className="relative"><img src={foto} alt="" className="w-full h-32 object-cover rounded-xl border-2 border-emerald-300" /><button onClick={() => setFoto(null)} className="absolute top-1 right-1 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs">✕</button></div>
            ) : (
              <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-stone-300 rounded-xl cursor-pointer hover:bg-stone-50">
                <span className="text-2xl">📷</span><span className="text-xs text-stone-400 mt-1">Tomar foto del camión</span>
                <input type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFoto} />
              </label>
            )}
          </div>
          <div>
            <label className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-1">Otras novedades (opcional)</label>
            <textarea value={novedades} onChange={e=>setNovedades(e.target.value)} placeholder="Cualquier otra observación..." rows={2} className="w-full border-2 border-stone-200 rounded-xl px-3 py-2 text-sm resize-none focus:border-indigo-400 outline-none" />
          </div>
        </div>
        <div className="px-5 pb-5 pt-3 space-y-2 border-t border-stone-100">
          {(cauchos==='mal'||danos==='grave') && (
            <div className="bg-red-50 border border-red-200 rounded-xl p-2 text-xs text-red-700 font-bold text-center">🚨 Se enviará alerta urgente al coordinador</div>
          )}
          <button onClick={submit} disabled={!canSubmit || submitting}
            className={`w-full py-3 rounded-xl font-black text-white text-base transition ${canSubmit && !submitting ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-stone-300 cursor-not-allowed'}`}>
            {submitting ? '⏳ Guardando...' : '🌙 Confirmar cierre de jornada'}
          </button>
          <button onClick={onBack} className="w-full py-2 text-xs text-stone-400 hover:text-stone-600">Cancelar</button>
        </div>
      </div>
    </div>
  );
}

function ChecklistScreen({ vehicle, driver, checklists, saveChecklists, onProceed, onBack, config, endShifts = [] }) {
  const todayKey = new Date().toISOString().slice(0, 10);
  const existing = checklists.find(c => c.vehicleId === vehicle.id && c.date === todayKey);
  // Alerta si el KM actual difiere del registrado al guardar
  const kmAlert = vehicle.lastParkedKm && vehicle.lastParkedDate && vehicle.lastParkedDate !== todayKey
    ? { lastKm: vehicle.lastParkedKm, lastDate: vehicle.lastParkedDate, lastTime: vehicle.lastParkedTime, currentKm: vehicle.currentKm }
    : null;
  // Último cierre de jornada de este camión
  const lastEndShift = endShifts.filter(s => s.vehicleId === vehicle.id).sort((a,b) => b.timestamp - a.timestamp)[0] || null;
  if (existing) {
    return <ChecklistAlreadyDone checklist={existing} vehicle={vehicle} driver={driver} onProceed={onProceed} onBack={onBack} />;
  }
  return <ChecklistForm vehicle={vehicle} driver={driver} saveChecklists={saveChecklists} checklists={checklists} onDone={onProceed} onBack={onBack} config={config} kmAlert={kmAlert} lastEndShift={lastEndShift} />;
}

// ============================================================
// PANTALLA: YA FUE CHEQUEADA HOY
// ============================================================
function ChecklistAlreadyDone({ checklist, vehicle, driver, onProceed, onBack }) {
  const [confirming, setConfirming] = useState(false);
  const hasCritical = checklist.items.some(i => i.value === 'bad');
  const hasWarn = checklist.items.some(i => i.value === 'warn');
  const criticalItems = checklist.items.filter(i => i.value === 'bad');
  const warnItems = checklist.items.filter(i => i.value === 'warn');
  const checkerName = checklist.driverName;
  const checkTime = checklist.time;

  return (
    <div className="space-y-4 pb-6">
      <div className="flex items-center gap-3 mb-2">
        <button onClick={onBack} className="p-2 rounded-xl bg-stone-100 hover:bg-stone-200 transition">
          <ArrowLeft className="w-5 h-5 text-stone-600" />
        </button>
        <div>
          <h2 className="font-bold text-stone-900 text-lg">Chequeo pre-viaje</h2>
          <p className="text-stone-500 text-xs">{vehicle.code} · {vehicle.plate}</p>
        </div>
      </div>

      {/* Banner principal */}
      <div className={`rounded-2xl p-4 border ${hasCritical ? 'bg-red-50 border-red-200' : hasWarn ? 'bg-amber-50 border-amber-200' : 'bg-emerald-50 border-emerald-200'}`}>
        <div className="flex items-start gap-3">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${hasCritical ? 'bg-red-100' : hasWarn ? 'bg-amber-100' : 'bg-emerald-100'}`}>
            {hasCritical ? <AlertTriangle className="w-5 h-5 text-red-600" /> : hasWarn ? <AlertTriangle className="w-5 h-5 text-amber-600" /> : <CheckCircle className="w-5 h-5 text-emerald-600" />}
          </div>
          <div className="flex-1 min-w-0">
            <div className={`font-bold text-sm ${hasCritical ? 'text-red-900' : hasWarn ? 'text-amber-900' : 'text-emerald-900'}`}>
              {hasCritical ? '⚠️ Unidad con fallas críticas' : hasWarn ? '🟡 Unidad con observaciones' : '✅ Unidad en buen estado'}
            </div>
            <div className={`text-xs mt-0.5 ${hasCritical ? 'text-red-700' : hasWarn ? 'text-amber-700' : 'text-emerald-700'}`}>
              Chequeada hoy por <strong>{checkerName}</strong> a las {checkTime}
            </div>
          </div>
        </div>
      </div>

      {/* Resumen de problemas */}
      {(hasCritical || hasWarn) && (
        <div className="bg-white border border-stone-200 rounded-2xl p-4">
          <div className="text-xs font-bold text-stone-500 uppercase tracking-wider mb-3">Novedades reportadas</div>
          <div className="space-y-2">
            {criticalItems.map(item => {
              const def = CHECKLIST_ITEMS.find(ci => ci.id === item.id);
              return (
                <div key={item.id} className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-red-500 flex-shrink-0"></span>
                  <span className="text-sm text-stone-700 flex-1">{def?.label}</span>
                  <span className="text-xs font-semibold text-red-600 bg-red-50 px-2 py-0.5 rounded-full">{def?.bad}</span>
                </div>
              );
            })}
            {warnItems.map(item => {
              const def = CHECKLIST_ITEMS.find(ci => ci.id === item.id);
              return (
                <div key={item.id} className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-amber-500 flex-shrink-0"></span>
                  <span className="text-sm text-stone-700 flex-1">{def?.label}</span>
                  <span className="text-xs font-semibold text-amber-700 bg-amber-50 px-2 py-0.5 rounded-full">{def?.warn}</span>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Advertencia si hay fallas críticas y es otro chofer */}
      {hasCritical && !confirming && driver.id !== checklist.driverId && (
        <div className="bg-orange-50 border border-orange-200 rounded-xl p-3 text-sm text-orange-800">
          <strong>Atención:</strong> Esta unidad tiene fallas críticas reportadas. Si vas al taller, conduce con precaución y baja velocidad.
        </div>
      )}

      {/* Botones */}
      {hasCritical && !confirming ? (
        <button
          onClick={() => setConfirming(true)}
          className="w-full py-4 rounded-2xl font-bold text-white bg-orange-500 hover:bg-orange-600 transition flex items-center justify-center gap-2 shadow-lg active:scale-[0.98]">
          <AlertTriangle className="w-5 h-5" /> Continuar de todas formas
        </button>
      ) : (
        <button
          onClick={() => onProceed(checklist.kmInicial || checklist.kmOdometer || '')}
          className="w-full py-4 rounded-2xl font-bold text-white bg-emerald-600 hover:bg-emerald-700 transition flex items-center justify-center gap-2 shadow-lg active:scale-[0.98]">
          <CheckCircle className="w-5 h-5" /> Iniciar viaje
        </button>
      )}
    </div>
  );
}

// ============================================================
// CANVAS DE FIRMA TÁCTIL
// ============================================================
function SignatureCanvas({ onSignature, cleared }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const hasSig = useRef(false);

  const getPos = (e, canvas) => {
    const r = canvas.getBoundingClientRect();
    const src = e.touches ? e.touches[0] : e;
    return { x: (src.clientX - r.left) * (canvas.width / r.width), y: (src.clientY - r.top) * (canvas.height / r.height) };
  };

  const clearCanvas = (canvas) => {
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  };

  const startDraw = (e) => {
    e.preventDefault();
    drawing.current = true;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const pos = getPos(e, canvas);
    ctx.beginPath();
    ctx.moveTo(pos.x, pos.y);
  };
  const draw = (e) => {
    e.preventDefault();
    if (!drawing.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const pos = getPos(e, canvas);
    ctx.lineWidth = 2.5;
    ctx.lineCap = 'round';
    ctx.strokeStyle = '#1c1917';
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    hasSig.current = true;
  };
  const endDraw = () => {
    drawing.current = false;
    if (hasSig.current) {
      onSignature(canvasRef.current.toDataURL('image/png'));
    }
  };
  const clear = () => {
    const canvas = canvasRef.current;
    clearCanvas(canvas);
    hasSig.current = false;
    onSignature(null);
  };

  useEffect(() => { if (cleared > 0) clear(); }, [cleared]);
  useEffect(() => { if (canvasRef.current) clearCanvas(canvasRef.current); }, []);

  return (
    <div>
      <canvas ref={canvasRef} width={600} height={180}
        onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
        onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}
        style={{ width: '100%', height: '140px', background: '#fafaf9', borderRadius: '12px', border: '1.5px dashed #d4c9c0', touchAction: 'none', cursor: 'crosshair', display: 'block' }}
      />
      <button onClick={clear} className="mt-2 text-xs text-stone-500 flex items-center gap-1 hover:text-stone-700 transition px-2 py-1 rounded-lg hover:bg-stone-100">
        <Eraser className="w-3.5 h-3.5" /> Borrar firma
      </button>
    </div>
  );
}

// ============================================================
// FORMULARIO COMPLETO DEL CHECKLIST
// ============================================================
function ChecklistForm({ vehicle, driver, saveChecklists, checklists, onDone, onBack, config, kmAlert, lastEndShift }) {
  const now = new Date();
  const todayKey = now.toISOString().slice(0, 10);
  const timeNow = now.toTimeString().slice(0, 5);

  // Estado: { itemId: 'ok' | 'warn' | 'bad' | null }
  const [values, setValues] = useState({});
  const [notes, setNotes] = useState({});   // { itemId: texto }
  const [photos, setPhotos] = useState({}); // { itemId: dataUrl }
  const [reporte, setReporte] = useState('');
  const [signature, setSignature] = useState(null);
  const [clearSig, setClearSig] = useState(0);
  const [finalPhoto, setFinalPhoto] = useState(null);
  const [unitPhotos, setUnitPhotos] = useState([]);
  const [kmInicial, setKmInicial] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  const allAnswered = CHECKLIST_ITEMS.every(i => values[i.id]);
  const hasSignature = !!signature;
  const hasFinalPhoto = !!finalPhoto;
  const criticalItems = CHECKLIST_ITEMS.filter(i => values[i.id] === 'bad');
  const warnItems = CHECKLIST_ITEMS.filter(i => values[i.id] === 'warn');
  const canSubmit = allAnswered && hasSignature && hasFinalPhoto;

  const groups = [
    { id: 'seguridad', label: 'Seguridad', color: 'red', items: CHECKLIST_ITEMS.filter(i => i.group === 'seguridad') },
    { id: 'mecanica', label: 'Mecánica y niveles', color: 'amber', items: CHECKLIST_ITEMS.filter(i => i.group === 'mecanica') },
    { id: 'docs', label: 'Documentos', color: 'blue', items: CHECKLIST_ITEMS.filter(i => i.group === 'docs') },
  ];

  const handlePhoto = (itemId, e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => setPhotos(p => ({ ...p, [itemId]: ev.target.result }));
    reader.readAsDataURL(file);
  };

  const handleUnitPhoto = (e) => {
    const files = Array.from(e.target.files || []);
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = ev => setUnitPhotos(p => [...p, ev.target.result]);
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const handleFinalPhoto = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => setFinalPhoto(ev.target.result);
    reader.readAsDataURL(file);
  };

  const handleSubmit = async () => {
    if (!canSubmit) {
      if (!allAnswered) setError('Completa todos los 14 ítems antes de enviar.');
      else if (!hasSignature) setError('Falta tu firma en el recuadro.');
      else if (!hasFinalPhoto) setError('Falta tomar la foto de respaldo final.');
      return;
    }
    setSubmitting(true);
    setError('');

    const checklist = {
      id: `chk_${Date.now()}`,
      vehicleId: vehicle.id,
      vehicleCode: vehicle.code,
      vehiclePlate: vehicle.plate,
      driverId: driver.id,
      driverName: driver.name,
      date: todayKey,
      time: timeNow,
      kmInicial: kmInicial || '',
      items: CHECKLIST_ITEMS.map(i => ({
        id: i.id,
        value: values[i.id],
        note: notes[i.id] || '',
        photo: values[i.id] === 'bad' ? (photos[i.id] || null) : null,
      })),
      criticalCount: criticalItems.length,
      warningCount: warnItems.length,
      reporte,
      signature,
      finalPhoto,
      unitPhotos,
      createdAt: Date.now(),
    };

    saveChecklists([...checklists, checklist]);

   // Notificación Discord — SIEMPRE
        await sendChecklistDiscord(checklist, vehicle, driver, config);

    setSubmitting(false);
    onDone(kmInicial || '');
  };

  const groupColors = {
    red:   { dot: 'bg-red-500',    label: 'text-red-700',    header: 'text-red-700' },
    amber: { dot: 'bg-amber-500',  label: 'text-amber-700',  header: 'text-amber-700' },
    blue:  { dot: 'bg-blue-500',   label: 'text-blue-700',   header: 'text-blue-700' },
  };

  const btnBase = 'w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold transition border flex-shrink-0';
  const btnOk   = (sel) => sel === 'ok'   ? `${btnBase} bg-emerald-100 text-emerald-700 border-emerald-300 shadow-sm scale-105` : `${btnBase} bg-stone-100 text-stone-400 border-stone-200 hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200`;
  const btnWarn = (sel) => sel === 'warn' ? `${btnBase} bg-amber-100 text-amber-700 border-amber-300 shadow-sm scale-105`   : `${btnBase} bg-stone-100 text-stone-400 border-stone-200 hover:bg-amber-50 hover:text-amber-600 hover:border-amber-200`;
  const btnBad  = (sel) => sel === 'bad'  ? `${btnBase} bg-red-100 text-red-600 border-red-300 shadow-sm scale-105`          : `${btnBase} bg-stone-100 text-stone-400 border-stone-200 hover:bg-red-50 hover:text-red-500 hover:border-red-200`;

  const answered = Object.values(values).filter(Boolean).length;

  return (
    <div className="space-y-4 pb-8">
      {/* ALERTA KM — camión movido sin autorización */}
      {kmAlert && kmAlert.currentKm > kmAlert.lastKm && (
        <div className="bg-red-50 border-2 border-red-400 rounded-2xl p-4">
          <div className="flex items-start gap-3">
            <div className="text-2xl">🚨</div>
            <div>
              <div className="font-black text-red-800 text-sm">¡El camión fue movido!</div>
              <div className="text-xs text-red-700 mt-1 space-y-0.5">
                <div>🌙 Guardado ayer ({kmAlert.lastDate} {kmAlert.lastTime}): <strong>{kmAlert.lastKm.toLocaleString()} km</strong></div>
                <div>🌅 KM actual: <strong>{(kmAlert.currentKm||0).toLocaleString()} km</strong></div>
                <div className="font-bold text-red-800">⚠️ Diferencia: +{((kmAlert.currentKm||0) - kmAlert.lastKm).toLocaleString()} km SIN AUTORIZACIÓN</div>
              </div>
            </div>
          </div>
        </div>
      )}
      {/* CIERRE DE JORNADA ANTERIOR */}
      {lastEndShift && (
        <div className="bg-indigo-50 border-2 border-indigo-200 rounded-2xl p-4">
          <div className="text-xs font-bold text-indigo-700 uppercase tracking-wider mb-2">🌙 Cierre jornada anterior — {lastEndShift.driverName}</div>
          <div className="grid grid-cols-2 gap-2 text-xs mb-2">
            <div className="bg-white rounded-lg p-2 border border-indigo-100">
              <div className="text-indigo-400 font-mono">📅 Fecha</div>
              <div className="font-bold text-indigo-900">{lastEndShift.date} {lastEndShift.time}</div>
            </div>
            <div className="bg-white rounded-lg p-2 border border-indigo-100">
              <div className="text-indigo-400 font-mono">🔢 KM guardado</div>
              <div className="font-bold text-indigo-900">{(lastEndShift.kmFinal||0).toLocaleString()} km</div>
            </div>
            <div className="bg-white rounded-lg p-2 border border-indigo-100">
              <div className="text-indigo-400 font-mono">🔵 Cauchos</div>
              <div className={`font-bold ${lastEndShift.items?.cauchos==='mal'?'text-red-600':lastEndShift.items?.cauchos==='revisar'?'text-amber-600':'text-emerald-700'}`}>
                {lastEndShift.items?.cauchos==='bien'?'✅ Bien':lastEndShift.items?.cauchos==='revisar'?'⚠️ Revisar':lastEndShift.items?.cauchos==='mal'?'🔴 Mal estado':'—'}
              </div>
            </div>
            <div className="bg-white rounded-lg p-2 border border-indigo-100">
              <div className="text-indigo-400 font-mono">🔍 Daños</div>
              <div className={`font-bold ${lastEndShift.items?.danos==='grave'?'text-red-600':lastEndShift.items?.danos==='menor'?'text-amber-600':'text-emerald-700'}`}>
                {lastEndShift.items?.danos==='ninguno'?'✅ Ninguno':lastEndShift.items?.danos==='menor'?'⚠️ Menor':lastEndShift.items?.danos==='grave'?'🔴 Grave':'—'}
              </div>
            </div>
          </div>
          {lastEndShift.cauchoNota && lastEndShift.items?.cauchos !== 'bien' && (
            <div className="text-xs text-amber-700 bg-amber-50 rounded-lg p-2 mb-1">🔵 {lastEndShift.cauchoNota}</div>
          )}
          {lastEndShift.danosNota && lastEndShift.items?.danos !== 'ninguno' && (
            <div className="text-xs text-red-700 bg-red-50 rounded-lg p-2 mb-1">🔍 {lastEndShift.danosNota}</div>
          )}
          {lastEndShift.fotoChofer && (
            <div className="flex items-center gap-2 mt-2">
              <img src={lastEndShift.fotoChofer} alt="Chofer" className="w-16 h-16 object-cover rounded-xl border-2 border-indigo-200" />
              <div className="text-xs text-indigo-600">🧑 {lastEndShift.driverName}</div>
            </div>
          )}
          {lastEndShift.foto && (
            <img src={lastEndShift.foto} alt="Foto cierre" className="w-full h-24 object-cover rounded-xl mt-2 border border-indigo-200" />
          )}
          {lastEndShift.novedades && (
            <div className="text-xs text-stone-600 mt-1">📝 {lastEndShift.novedades}</div>
          )}
        </div>
      )}
      {/* Header */}
      <div className="flex items-center gap-3">
        <button onClick={onBack} className="p-2 rounded-xl bg-stone-100 hover:bg-stone-200 transition">
          <ArrowLeft className="w-5 h-5 text-stone-600" />
        </button>
        <div className="flex-1">
          <h2 className="font-bold text-stone-900 text-lg">Chequeo pre-viaje</h2>
          <p className="text-stone-500 text-xs">{vehicle.code} · {vehicle.plate} · {timeNow}</p>
        </div>
        <div className="text-right">
          <div className="text-lg font-black text-stone-900">{answered}/14</div>
          <div className="text-[10px] text-stone-400 uppercase tracking-wider">ítems</div>
        </div>
      </div>

      {/* Info chofer + km */}
      <div className="bg-stone-50 border border-stone-200 rounded-2xl p-3 flex gap-3">
        <div className="flex-1">
          <div className="text-[10px] text-stone-400 uppercase tracking-wider mb-0.5">Chofer</div>
          <div className="font-semibold text-stone-800 text-sm">{driver.name}</div>
        </div>
        <div className="flex-1">
          <label className="text-[10px] text-stone-400 uppercase tracking-wider block mb-0.5">Km odómetro</label>
          <input type="number" value={kmInicial} onChange={e => setKmInicial(e.target.value)}
            placeholder={String(vehicle.currentKm || 0)}
            className="w-full text-sm font-bold bg-white border border-stone-300 rounded-lg px-2 py-1 outline-none focus:border-emerald-400" />
        </div>
      </div>

      {/* Items por grupo */}
      {groups.map(group => {
        const gc = groupColors[group.color];
        return (
          <div key={group.id}>
            <div className="flex items-center gap-2 mb-2">
              <div className={`w-2 h-2 rounded-full ${gc.dot}`}></div>
              <span className={`text-xs font-bold uppercase tracking-widest ${gc.header}`}>{group.label}</span>
            </div>
            <div className="space-y-2">
              {group.items.map(item => {
                const sel = values[item.id] || null;
                const showExtra = sel === 'bad';
                return (
                  <div key={item.id} className={`bg-white border rounded-2xl overflow-hidden transition ${showExtra ? 'border-red-200 shadow-sm' : 'border-stone-200'}`}>
                    <div className="flex items-center gap-3 px-3 py-2.5">
                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-medium text-stone-800 leading-tight">{item.label}</div>
                        <div className="text-[10px] mt-0.5 flex gap-2">
                          <span className="text-emerald-600 font-medium">{item.ok}</span>
                          <span className="text-stone-300">·</span>
                          <span className="text-amber-600 font-medium">{item.warn}</span>
                          <span className="text-stone-300">·</span>
                          <span className="text-red-500 font-medium">{item.bad}</span>
                        </div>
                      </div>
                      <div className="flex gap-1.5 flex-shrink-0">
                        <button className={btnOk(sel)} onClick={() => setValues(v => ({ ...v, [item.id]: 'ok' }))}>
                          <CheckCheck className="w-4 h-4" />
                        </button>
                        <button className={btnWarn(sel)} onClick={() => setValues(v => ({ ...v, [item.id]: 'warn' }))}>
                          <span style={{ fontSize: item.warnBtn.length > 1 ? '10px' : '13px' }}>{item.warnBtn}</span>
                        </button>
                        <button className={btnBad(sel)} onClick={() => setValues(v => ({ ...v, [item.id]: 'bad' }))}>
                          <span style={{ fontSize: item.badBtn.length > 1 ? '10px' : '13px' }}>{item.badBtn}</span>
                        </button>
                      </div>
                    </div>
                    {/* Expansión cuando es rojo */}
                    {showExtra && (
                      <div className="bg-red-50 border-t border-red-100 px-3 py-2.5 space-y-2">
                        <div className="text-xs font-semibold text-red-700 flex items-center gap-1.5">
                          <Camera className="w-3.5 h-3.5" /> Foto y nota requeridas
                        </div>
                        <label className="block w-full">
                          <input type="file" accept="image/*" capture="environment" className="sr-only"
                            onChange={e => handlePhoto(item.id, e)} />
                          <div className="flex items-center justify-center gap-2 py-2 bg-white border border-red-200 rounded-xl text-xs font-semibold text-red-600 cursor-pointer hover:bg-red-50 transition">
                            {photos[item.id]
                              ? <><CheckCheck className="w-3.5 h-3.5" /> Foto tomada ✓</>
                              : <><Camera className="w-3.5 h-3.5" /> Tomar foto</>
                            }
                          </div>
                        </label>
                        <input type="text" value={notes[item.id] || ''} onChange={e => setNotes(n => ({ ...n, [item.id]: e.target.value }))}
                          placeholder="Describe el problema..."
                          className="w-full text-xs bg-white border border-red-200 rounded-xl px-3 py-2 outline-none focus:border-red-400" />
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}

      {/* Reporte de novedades */}
      <div>
        <label className="text-xs font-bold text-stone-500 uppercase tracking-wider block mb-2">
          Reporte de novedades <span className="text-stone-400 font-normal normal-case">(opcional)</span>
        </label>
        <textarea rows={3} value={reporte} onChange={e => setReporte(e.target.value)}
          placeholder="Ej: vibración en el volante al pasar de 60 km/h..."
          className="w-full bg-white border border-stone-200 rounded-2xl px-3 py-2.5 text-sm outline-none focus:border-emerald-400 resize-none" />
      </div>

      {/* Fotos de la unidad */}
      <div>
        <label className="text-xs font-bold text-stone-500 uppercase tracking-wider block mb-2">
          📷 Fotos de la unidad <span className="text-stone-400 font-normal normal-case">(opcional — toma las que quieras)</span>
        </label>
        <div className="flex flex-wrap gap-2 mb-2">
          {unitPhotos.map((p, i) => (
            <div key={i} className="relative w-20 h-20 rounded-xl overflow-hidden border border-stone-200 flex-shrink-0">
              <img src={p} alt={`Foto ${i+1}`} className="w-full h-full object-cover" />
              <button type="button" onClick={() => setUnitPhotos(ps => ps.filter((_, j) => j !== i))}
                className="absolute top-0.5 right-0.5 bg-red-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs font-bold shadow">
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
          <label className="w-20 h-20 rounded-xl border-2 border-dashed border-stone-300 flex flex-col items-center justify-center cursor-pointer hover:border-emerald-400 hover:bg-emerald-50 transition flex-shrink-0">
            <Camera className="w-6 h-6 text-stone-400" />
            <span className="text-[10px] text-stone-400 mt-1">Agregar</span>
            <input type="file" accept="image/*" capture="environment" className="sr-only" onChange={handleUnitPhoto} />
          </label>
        </div>
        {unitPhotos.length > 0 && (
          <p className="text-[10px] text-stone-400">{unitPhotos.length} foto{unitPhotos.length > 1 ? 's' : ''} — se enviarán al Discord</p>
        )}
      </div>

      {/* Firma + Foto de Respaldo Final (lado a lado en pantallas grandes, apilados en móvil) */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        {/* FIRMA */}
        <div>
          <label className="text-xs font-bold text-stone-500 uppercase tracking-wider block mb-2">
            Firma del chofer <span className="text-stone-400 font-normal normal-case">(dibuja con el dedo)</span>
            {!hasSignature && <span className="text-red-500 ml-1">*</span>}
          </label>
          <SignatureCanvas onSignature={setSignature} cleared={clearSig} />
        </div>

        {/* FOTO DE RESPALDO FINAL */}
        <div>
          <label className="text-xs font-bold text-stone-500 uppercase tracking-wider block mb-2">
            Foto de respaldo final <span className="text-stone-400 font-normal normal-case">(chofer + unidad)</span>
            {!hasFinalPhoto && <span className="text-red-500 ml-1">*</span>}
          </label>
          {finalPhoto ? (
            <div className="relative">
              <img src={finalPhoto} alt="Foto de respaldo final"
                style={{ width: '100%', height: '140px', objectFit: 'cover', borderRadius: '12px', border: '1.5px solid #10b981', display: 'block' }} />
              <div className="absolute top-2 right-2 flex gap-1">
                <label className="bg-white/90 backdrop-blur rounded-lg px-2 py-1 text-[10px] font-bold text-stone-700 cursor-pointer hover:bg-white transition flex items-center gap-1 shadow">
                  <Camera className="w-3 h-3" /> Cambiar
                  <input type="file" accept="image/*" capture="environment" className="sr-only" onChange={handleFinalPhoto} />
                </label>
                <button type="button" onClick={() => setFinalPhoto(null)}
                  className="bg-white/90 backdrop-blur rounded-lg px-2 py-1 text-[10px] font-bold text-red-600 hover:bg-white transition flex items-center gap-1 shadow">
                  <X className="w-3 h-3" /> Borrar
                </button>
              </div>
              <div className="absolute bottom-2 left-2 bg-emerald-600 text-white text-[10px] font-bold px-2 py-1 rounded-lg flex items-center gap-1 shadow">
                <CheckCheck className="w-3 h-3" /> Foto tomada
              </div>
            </div>
          ) : (
            <label className="block w-full cursor-pointer">
              <input type="file" accept="image/*" capture="environment" className="sr-only" onChange={handleFinalPhoto} />
              <div style={{ width: '100%', height: '140px', background: '#fafaf9', borderRadius: '12px', border: '1.5px dashed #d4c9c0' }}
                className="flex flex-col items-center justify-center gap-1.5 hover:bg-stone-100 hover:border-emerald-300 transition">
                <Camera className="w-7 h-7 text-stone-400" />
                <span className="text-xs text-stone-500 font-medium">Tomar foto de respaldo</span>
                <span className="text-[10px] text-stone-400">Activar cámara</span>
              </div>
            </label>
          )}
          <div className="mt-2 text-[10px] text-stone-400 flex items-start gap-1">
            <Info className="w-3 h-3 mt-0.5 flex-shrink-0" />
            <span>Foto obligatoria del chofer con la unidad antes de salir.</span>
          </div>
        </div>
      </div>

      {/* Banner fallas críticas */}
      {criticalItems.length > 0 && (
        <div className="bg-blue-50 border border-blue-200 rounded-2xl p-3">
          <div className="flex items-start gap-2">
            <Info className="w-4 h-4 text-blue-600 flex-shrink-0 mt-0.5" />
            <p className="text-xs text-blue-800">
              <strong>Reportaste {criticalItems.length} falla{criticalItems.length > 1 ? 's' : ''} crítica{criticalItems.length > 1 ? 's' : ''}.</strong> Se enviará informe inmediato al coordinador. El viaje no está bloqueado — si vas al taller, conduce con precaución.
            </p>
          </div>
        </div>
      )}

      {/* Error */}
      {error && <div className="bg-red-50 border border-red-200 rounded-xl p-3 text-xs text-red-700">{error}</div>}

      {/* Botón enviar */}
      <button onClick={handleSubmit} disabled={!canSubmit || submitting}
        className={`w-full py-4 rounded-2xl font-bold text-sm transition flex items-center justify-center gap-2 shadow-lg active:scale-[0.98] ${canSubmit && !submitting ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : 'bg-stone-200 text-stone-400 cursor-not-allowed'}`}>
        {submitting
          ? <><div className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin"></div> Enviando...</>
          : <><ShieldCheck className="w-5 h-5" /> Finalizar y enviar chequeo</>
        }
      </button>
      {!canSubmit && (
        <p className="text-center text-xs text-stone-400">
          {!allAnswered
            ? `Faltan ${14 - answered} ítem${14 - answered > 1 ? 's' : ''} por responder`
            : !hasSignature
              ? 'Firma requerida para enviar'
              : 'Foto de respaldo final requerida'}
        </p>
      )}
    </div>
  );
}

// ============================================================
// WIDGET FLOTA — SEMÁFORO PARA EL DASHBOARD DEL COORDINADOR
// ============================================================
function FleetChecklistWidget({ vehicles, checklists, drivers, onSelect }) {
  const todayKey = new Date().toISOString().slice(0, 10);
  const todayChecklists = checklists.filter(c => c.date === todayKey);

  const getStatus = (vehicleId) => {
    const c = todayChecklists.find(c => c.vehicleId === vehicleId);
    if (!c) return 'none';
    if (c.items.some(i => i.value === 'bad')) return 'bad';
    if (c.items.some(i => i.value === 'warn')) return 'warn';
    return 'ok';
  };

  const counts = {
    ok:   vehicles.filter(v => getStatus(v.id) === 'ok').length,
    warn: vehicles.filter(v => getStatus(v.id) === 'warn').length,
    bad:  vehicles.filter(v => getStatus(v.id) === 'bad').length,
    none: vehicles.filter(v => getStatus(v.id) === 'none').length,
  };

  const statusColors = {
    ok:   { bg: 'bg-emerald-50', border: 'border-emerald-200', dot: 'bg-emerald-500', text: 'text-emerald-700', label: 'Operativas' },
    warn: { bg: 'bg-amber-50',   border: 'border-amber-200',   dot: 'bg-amber-500',   text: 'text-amber-700',   label: 'Observadas' },
    bad:  { bg: 'bg-red-50',     border: 'border-red-200',     dot: 'bg-red-500',     text: 'text-red-700',     label: 'Con fallas' },
    none: { bg: 'bg-stone-50',   border: 'border-stone-200',   dot: 'bg-stone-400',   text: 'text-stone-500',   label: 'Sin chequeo' },
  };

  return (
    <div className="bg-white border border-stone-200 rounded-2xl p-4 shadow-sm">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h3 className="font-bold text-stone-800 text-sm">Chequeos pre-viaje hoy</h3>
          <p className="text-xs text-stone-400">{todayChecklists.length} de {vehicles.length} unidades chequeadas</p>
        </div>
        <ClipboardCheck className="w-5 h-5 text-stone-400" />
      </div>

      {/* Semáforos */}
      <div className="grid grid-cols-4 gap-2 mb-4">
        {['ok','warn','bad','none'].map(s => {
          const c = statusColors[s];
          return (
            <div key={s} className={`${c.bg} border ${c.border} rounded-xl p-2 text-center`}>
              <div className="flex justify-center mb-1"><div className={`w-3 h-3 rounded-full ${c.dot}`}></div></div>
              <div className={`text-xl font-black ${c.text}`}>{counts[s]}</div>
              <div className={`text-[9px] font-semibold uppercase tracking-wider ${c.text} leading-tight`}>{c.label}</div>
            </div>
          );
        })}
      </div>

      {/* Lista de chequeos del día */}
      {todayChecklists.length > 0 && (
        <div className="space-y-2">
          {todayChecklists.map(c => {
            const v = vehicles.find(v => v.id === c.vehicleId);
            const hasBad  = c.items.some(i => i.value === 'bad');
            const hasWarn = c.items.some(i => i.value === 'warn');
            const badCount  = c.items.filter(i => i.value === 'bad').length;
            const warnCount = c.items.filter(i => i.value === 'warn').length;
            return (
              <div key={c.id} onClick={() => onSelect && onSelect(c)} className={`flex items-center gap-3 p-2.5 bg-stone-50 border border-stone-100 rounded-xl transition ${onSelect ? 'cursor-pointer hover:bg-stone-100 hover:border-stone-200' : ''}`}>
                <div className={`w-2.5 h-2.5 rounded-full flex-shrink-0 ${hasBad ? 'bg-red-500' : hasWarn ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-stone-800 text-xs">{v?.code || c.vehicleCode}</div>
                  <div className="text-[10px] text-stone-500">{c.driverName} · {c.time}</div>
                </div>
                <div className="flex gap-1 text-[10px]">
                  {hasBad  && <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded-full font-semibold">{badCount} 🔴</span>}
                  {hasWarn && <span className="bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full font-semibold">{warnCount} 🟡</span>}
                  {!hasBad && !hasWarn && <span className="bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded-full font-semibold">✅ OK</span>}
                </div>
              </div>
            );
          })}
          {/* Unidades sin chequeo hoy */}
          {vehicles.filter(v => !todayChecklists.find(c => c.vehicleId === v.id)).map(v => (
            <div key={v.id} className="flex items-center gap-3 p-2.5 bg-stone-50 border border-stone-100 rounded-xl opacity-50">
              <div className="w-2.5 h-2.5 rounded-full flex-shrink-0 bg-stone-400"></div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-stone-600 text-xs">{v.code}</div>
                <div className="text-[10px] text-stone-400">Sin chequeo hoy</div>
              </div>
              <span className="text-[10px] text-stone-400">—</span>
            </div>
          ))}
        </div>
      )}
      {todayChecklists.length === 0 && (
        <div className="text-center py-4">
          <div className="text-stone-400 text-xs">Ninguna unidad chequeada hoy</div>
        </div>
      )}
    </div>
  );
}

// ============================================================
// MODAL DETALLE DEL CHEQUEO
// Muestra el chequeo completo: foto, firma, ítems, novedades
// Se abre al hacer click en un chequeo del widget
// ============================================================
function ChecklistDetailModal({ checklist, vehicles, onClose }) {
  const vehicle = vehicles.find(v => v.id === checklist.vehicleId);
  const criticalItems = (checklist.items || []).filter(i => i.value === 'bad');
  const warnItems = (checklist.items || []).filter(i => i.value === 'warn');
  const okItems = (checklist.items || []).filter(i => i.value === 'ok');
  const hasCritical = criticalItems.length > 0;
  const hasWarn = warnItems.length > 0;

  const statusBadge = hasCritical
    ? { bg: 'bg-red-100', text: 'text-red-700', label: '🔴 Con fallas críticas' }
    : hasWarn
      ? { bg: 'bg-amber-100', text: 'text-amber-700', label: '🟡 Con observaciones' }
      : { bg: 'bg-emerald-100', text: 'text-emerald-700', label: '✅ Todo en orden' };

  const groups = [
    { id: 'seguridad', label: '🔴 Seguridad', color: 'text-red-600' },
    { id: 'mecanica', label: '🟡 Mecánica y niveles', color: 'text-amber-600' },
    { id: 'docs', label: '🔵 Documentos', color: 'text-blue-600' },
  ];

  const valueColors = { ok: 'text-emerald-600 bg-emerald-50', warn: 'text-amber-600 bg-amber-50', bad: 'text-red-600 bg-red-50' };

  const handleWhatsApp = () => {
    const status = hasCritical ? '🔴 CON FALLAS CRÍTICAS' : hasWarn ? '🟡 CON OBSERVACIONES' : '✅ TODO EN ORDEN';
    const critList = criticalItems.map(i => {
      const def = CHECKLIST_ITEMS.find(ci => ci.id === i.id);
      return `🔴 ${def?.label}: ${def?.bad}${i.note ? ` (${i.note})` : ''}`;
    }).join('\n');
    const warnList = warnItems.map(i => {
      const def = CHECKLIST_ITEMS.find(ci => ci.id === i.id);
      return `🟡 ${def?.label}: ${def?.warn}${i.note ? ` (${i.note})` : ''}`;
    }).join('\n');
    const msg = `🚛 *CHEQUEO PRE-VIAJE*\n*${vehicle?.code || checklist.vehicleCode}* (${checklist.vehiclePlate})\n*${checklist.driverName}* · ${checklist.time} · ${checklist.date}\n\n${status}\n✅ OK: ${okItems.length} ítems\n🟡 Observaciones: ${warnItems.length}\n🔴 Críticos: ${criticalItems.length}\n${critList ? '\n' + critList : ''}${warnList ? '\n' + warnList : ''}${checklist.reporte ? `\n\n📝 *Novedad:* ${checklist.reporte}` : ''}\n\n✍️ Firmado digitalmente`;
    window.open(`https://wa.me/?text=${encodeURIComponent(msg)}`, '_blank');
  };

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center p-4 pt-8"
      style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)' }}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">

        {/* Header */}
        <div className="sticky top-0 bg-white border-b border-stone-200 px-5 py-4 flex items-center justify-between rounded-t-2xl z-10">
          <div>
            <div className="font-bold text-stone-900 text-base">{vehicle?.code || checklist.vehicleCode}</div>
            <div className="text-xs text-stone-500">{checklist.vehiclePlate} · {checklist.driverName} · {checklist.time}</div>
          </div>
          <div className="flex items-center gap-2">
            <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${statusBadge.bg} ${statusBadge.text}`}>
              {statusBadge.label}
            </span>
            <button onClick={onClose} className="w-8 h-8 rounded-full bg-stone-100 hover:bg-stone-200 flex items-center justify-center transition">
              <X className="w-4 h-4 text-stone-600" />
            </button>
          </div>
        </div>

        <div className="p-5 space-y-5">

          {/* Info general */}
          <div className="grid grid-cols-3 gap-2 text-center">
            <div className="bg-stone-50 rounded-xl p-2.5">
              <div className="text-lg font-black text-emerald-600">{okItems.length}</div>
              <div className="text-[10px] text-stone-400 uppercase tracking-wider">OK</div>
            </div>
            <div className="bg-stone-50 rounded-xl p-2.5">
              <div className="text-lg font-black text-amber-600">{warnItems.length}</div>
              <div className="text-[10px] text-stone-400 uppercase tracking-wider">Observ.</div>
            </div>
            <div className="bg-stone-50 rounded-xl p-2.5">
              <div className="text-lg font-black text-red-600">{criticalItems.length}</div>
              <div className="text-[10px] text-stone-400 uppercase tracking-wider">Críticos</div>
            </div>
          </div>

          {/* Firma + Foto lado a lado */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <div className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-2">Firma del chofer</div>
              {checklist.signature
                ? <img src={checklist.signature} alt="Firma" className="w-full rounded-xl border border-stone-200" style={{ height: '100px', objectFit: 'contain', background: '#fafaf9' }} />
                : <div className="w-full rounded-xl border border-stone-200 bg-stone-50 flex items-center justify-center text-xs text-stone-400" style={{ height: '100px' }}>Sin firma</div>
              }
            </div>
            <div>
              <div className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-2">Foto de respaldo</div>
              {checklist.finalPhoto
                ? <img src={checklist.finalPhoto} alt="Foto respaldo" className="w-full rounded-xl border border-stone-200" style={{ height: '100px', objectFit: 'cover' }} />
                : <div className="w-full rounded-xl border border-stone-200 bg-stone-50 flex items-center justify-center text-xs text-stone-400" style={{ height: '100px' }}>Sin foto</div>
              }
            </div>
          </div>

          {/* KM */}
          {checklist.kmInicial && (
            <div className="bg-stone-50 rounded-xl px-4 py-2.5 flex justify-between items-center">
              <span className="text-xs text-stone-500">Km odómetro</span>
              <span className="font-bold text-stone-800">{Number(checklist.kmInicial).toLocaleString()} km</span>
            </div>
          )}

          {/* Ítems por grupo */}
          {groups.map(group => {
            const groupItems = (checklist.items || []).filter(i => {
              const def = CHECKLIST_ITEMS.find(ci => ci.id === i.id);
              return def?.group === group.id;
            });
            if (!groupItems.length) return null;
            return (
              <div key={group.id}>
                <div className={`text-xs font-bold uppercase tracking-wider mb-2 ${group.color}`}>{group.label}</div>
                <div className="space-y-1.5">
                  {groupItems.map(item => {
                    const def = CHECKLIST_ITEMS.find(ci => ci.id === item.id);
                    const label = item.value === 'ok' ? def?.ok : item.value === 'warn' ? def?.warn : def?.bad;
                    const colorClass = valueColors[item.value] || 'text-stone-400 bg-stone-50';
                    return (
                      <div key={item.id} className="bg-white border border-stone-100 rounded-xl overflow-hidden">
                        <div className="flex items-center justify-between px-3 py-2">
                          <span className="text-sm text-stone-700">{def?.label}</span>
                          <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${colorClass}`}>{label}</span>
                        </div>
                        {item.note && (
                          <div className="px-3 pb-2 text-xs text-stone-500 italic">📝 {item.note}</div>
                        )}
                        {item.photo && (
                          <img src={item.photo} alt="Foto del ítem" className="w-full" style={{ maxHeight: '120px', objectFit: 'cover' }} />
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}

          {/* Reporte de novedades */}
          {checklist.reporte && (
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-3">
              <div className="text-xs font-bold text-amber-700 mb-1">📝 Reporte de novedades</div>
              <p className="text-sm text-amber-800">{checklist.reporte}</p>
            </div>
          )}

          {/* Botón WhatsApp */}
          <button onClick={handleWhatsApp}
            className="w-full py-3 rounded-2xl font-bold text-white text-sm flex items-center justify-center gap-2 transition active:scale-[0.98]"
            style={{ background: '#25D366' }}>
            <MessageCircle className="w-5 h-5" />
            Compartir resumen por WhatsApp
          </button>

        </div>
      </div>
    </div>
  );
}

async function sendChecklistDiscord(cl, vehicle, driver, config) {
  const webhookUrl = vehicle?.maintenanceWebhook || config?.discordWebhookMaintenance || config?.discordWebhookGeneral || '';
  if (!webhookUrl) return;
  const crits = cl.criticalCount || 0;
  const warns = cl.warningCount || 0;
  const status = crits > 0 ? '🔴 CRÍTICO' : warns > 0 ? '⚠️ REVISAR' : '✅ TODO BIEN';
    const allItems = typeof CHECKLIST_ITEMS !== 'undefined' ? CHECKLIST_ITEMS : [];
    const itemLines = allItems.map(item => {
      const found = (cl.items || []).find(i => i.id === item.id);
      const val = found ? found.value : null;
      const e = val === 'ok' ? '✅' : val === 'warn' ? '⚠️' : val === 'bad' ? '🔴' : '—';
      const label = val === 'ok' ? item.ok : val === 'warn' ? item.warn : val === 'bad' ? item.bad : '—';
      return `${e} **${item.label}**: ${label}`;
    }).join('\n');
  const embed = {
    title: `📋 CHEQUEO PRE-VIAJE · ${vehicle?.code} · ${status}`,
    description: `**${driver?.name}** completó el chequeo de **${vehicle?.code}** (${vehicle?.plate})`,
    color: crits > 0 ? 0xFF0000 : warns > 0 ? 0xFFA500 : 0x00AA55,
    fields: [
      { name: '📅 Fecha y hora', value: `${cl.date} a las ${cl.time || '—'}`, inline: true },
      { name: '🔢 Odómetro', value: `${(cl.kmOdometer || vehicle?.currentKm || 0).toLocaleString()} km`, inline: true },
      { name: '📊 Resultado', value: crits > 0 ? `🔴 ${crits} crítico(s)` : warns > 0 ? `⚠️ ${warns} para revisar` : '✅ Sin novedades', inline: true },
      { name: `📋 Detalle (${Object.keys(cl.items || {}).length} ítems)`, value: itemLines.slice(0, 1000) || '—' },
    ],
    footer: { text: `Transporte Emporium · ${new Date().toLocaleString('es-VE')}` },
    timestamp: new Date().toISOString(),
  };
  if (cl.reporte || cl.notas || cl.notes) embed.fields.push({ name: '📝 Novedades', value: cl.reporte || cl.notas || cl.notes });
  // Detalle de ítems críticos con notas
  const badItems = (cl.items || []).filter(i => i.value === 'bad');
  if (badItems.length > 0) {
    const badLines = badItems.map(i => {
      const def = allItems.find(ci => ci.id === i.id);
      return `🔴 **${def?.label || i.id}**: ${def?.bad || 'crítico'}${i.note ? ` — _${i.note}_` : ''}`;
    }).join('\n');
    embed.fields.push({ name: `🔴 Ítems críticos (${badItems.length})`, value: badLines.slice(0, 1000) });
  }
  embed.fields.push({ name: '✍️ Firma', value: (cl.firma || cl.signature) ? '✅ Firmado por el chofer' : '❌ Sin firma' });
  const fotoData = cl.finalPhoto || cl.foto || cl.photo;
  if (fotoData) {
    embed.image = { url: 'attachment://foto_checklist.jpg' };
    embed.fields.push({ name: '📸 Foto', value: '✅ Foto adjunta ↓' });
  } else {
    embed.fields.push({ name: '📸 Foto', value: '❌ Sin foto' });
  }
  // Fotos adicionales de la unidad
  const extraPhotos = cl.unitPhotos || [];
  if (extraPhotos.length > 0) {
    embed.fields.push({ name: '📷 Fotos de la unidad', value: `✅ ${extraPhotos.length} foto(s) adjunta(s)` });
  }
  // Enviar embed + foto adjunta en un solo mensaje
  if (fotoData && webhookUrl) {
    try {
      if (!navigator.onLine) throw new Error('offline');
      const blob = base64ToBlob(fotoData);
      const fd = new FormData();
      fd.append('files[0]', blob, 'foto_checklist.jpg');
      fd.append('payload_json', JSON.stringify({ embeds: [embed] }));
      const res = await fetch(webhookUrl, { method: 'POST', body: fd });
      if (!res.ok) throw new Error('http ' + res.status);
    } catch(e) {
      // Offline o error → guardar en cola
      await idbAdd({ type: 'discord', webhookUrl, content: '📸 Foto checklist', photoData: fotoData, filename: 'foto_checklist.jpg', embed, queuedAt: new Date().toISOString() });
      // Enviar solo embed sin foto (notificación inmediata)
      await sendDiscordNotification(webhookUrl, { ...embed, image: undefined });
    }
  } else {
    await sendDiscordNotification(webhookUrl, embed);
  }
  // Enviar fotos de ítems críticos
  for (const item of badItems) {
    if (!item.photo) continue;
    const def = allItems.find(ci => ci.id === item.id);
    try {
      const blob = base64ToBlob(item.photo);
      const fd = new FormData();
      fd.append('files[0]', blob, `falla_${item.id}.jpg`);
      fd.append('payload_json', JSON.stringify({ content: `🔴 **Falla crítica: ${def?.label || item.id}**${item.note ? ` — ${item.note}` : ''} · ${vehicle?.code}` }));
      if (navigator.onLine) await fetch(webhookUrl, { method: 'POST', body: fd });
      else await idbAdd({ type: 'discord', webhookUrl, content: `🔴 Falla: ${def?.label}`, photoData: item.photo, filename: `falla_${item.id}.jpg`, embed: null, queuedAt: new Date().toISOString() });
    } catch(e) {
      await idbAdd({ type: 'discord', webhookUrl, content: `🔴 Falla: ${def?.label}`, photoData: item.photo, filename: `falla_${item.id}.jpg`, embed: null, queuedAt: new Date().toISOString() });
    }
  }
  // Enviar fotos adicionales de la unidad
  for (let idx = 0; idx < extraPhotos.length; idx++) {
    try {
      const blob = base64ToBlob(extraPhotos[idx]);
      const fd = new FormData();
      fd.append('files[0]', blob, `foto_unidad_${idx+1}.jpg`);
      fd.append('payload_json', JSON.stringify({ content: `📷 Foto de la unidad ${idx+1}/${extraPhotos.length} · ${vehicle?.code}` }));
      if (navigator.onLine) await fetch(webhookUrl, { method: 'POST', body: fd });
      else await idbAdd({ type: 'discord', webhookUrl, content: `📷 Foto unidad ${idx+1}`, photoData: extraPhotos[idx], filename: `foto_unidad_${idx+1}.jpg`, embed: null, queuedAt: new Date().toISOString() });
    } catch(e) {
      await idbAdd({ type: 'discord', webhookUrl, content: `📷 Foto unidad ${idx+1}`, photoData: extraPhotos[idx], filename: `foto_unidad_${idx+1}.jpg`, embed: null, queuedAt: new Date().toISOString() });
    }
  }
}
// ============================================================
// ChecklistCoordTab — vista para el coordinador con PDF
// ============================================================
function ChecklistCoordTab({ checklists, vehicles, drivers, config, saveChecklists, sbFetch: sbF }) {
  const [filterDate, setFilterDate] = useState(new Date().toISOString().slice(0, 10));
  const [filterVehicle, setFilterVehicle] = useState('all');
  const [deleteUntil, setDeleteUntil] = useState('');
  const [deleteVehicle, setDeleteVehicle] = useState('all');
  const handleDeleteOld = async () => {
    if (!deleteUntil) {
      alert('Selecciona una fecha primero');
      return;
    }
    const vehicleName = deleteVehicle === 'all' ? 'todas las unidades' : (vehicles.find(v => v.id === deleteVehicle)?.code || deleteVehicle);
    const toDelete = checklists.filter(c => c.date < deleteUntil && (deleteVehicle === 'all' || c.vehicleId === deleteVehicle)).length;
    if (toDelete === 0) { alert(`No hay checklists de ${vehicleName} anteriores al ${deleteUntil}`); return; }
    if (!window.confirm(`¿Borrar ${toDelete} checklist(s) de ${vehicleName} anteriores al ${deleteUntil}?`)) return;
    const keep = checklists.filter(c => !(c.date < deleteUntil && (deleteVehicle === 'all' || c.vehicleId === deleteVehicle)));
    saveChecklists(keep);
    if (sbF) { const q = deleteVehicle === 'all' ? `checklists?date=lt.${deleteUntil}` : `checklists?date=lt.${deleteUntil}&vehicle_id=eq.${deleteVehicle}`; sbF(q, { method: 'DELETE' }).catch(() => {}); }
  };
  const filtered = (checklists || [])
    .filter(c => (!filterDate || c.date === filterDate) && (filterVehicle === 'all' || c.vehicleId === filterVehicle))
    .sort((a, b) => b.createdAt - a.createdAt);
  const openPDF = (cl) => {
    const v = vehicles.find(x => x.id === cl.vehicleId);
    const d = drivers.find(x => x.id === cl.driverId);
    const crits = cl.criticalCount || 0;
    const warns = cl.warningCount || 0;
    const statusBadge = crits > 0
      ? `<span style="background:#fee2e2;color:#991b1b;padding:3px 10px;border-radius:9999px;font-size:11px;font-weight:700">🔴 ${crits} CRÍTICO(S)</span>`
      : warns > 0
      ? `<span style="background:#fef3c7;color:#92400e;padding:3px 10px;border-radius:9999px;font-size:11px;font-weight:700">⚠️ ${warns} REVISAR</span>`
      : `<span style="background:#d1fae5;color:#065f46;padding:3px 10px;border-radius:9999px;font-size:11px;font-weight:700">✅ TODO BIEN</span>`;
    const allItems = typeof CHECKLIST_ITEMS !== 'undefined' ? CHECKLIST_ITEMS : [];
    const rows = allItems.map(item => {
      const found = (cl.items || []).find(i => i.id === item.id);
      const val = found ? found.value : null;
      const opts = item.options || item.opts || [];
      const opt = opts.find(o => o.v === val);
      const idx = opt ? opts.indexOf(opt) : -1;
      const e = val === 'ok' ? '✅' : val === 'warn' ? '⚠️' : val === 'bad' ? '🔴' : '—';
      const label = val === 'ok' ? (item.ok || 'bien') : val === 'warn' ? (item.warn || 'revisar') : val === 'bad' ? (item.bad || 'mal') : (opt?.l || opt?.label || val || '—');
      const bg = idx === 0 ? '#d1fae5' : idx === 1 ? '#fef3c7' : idx === 2 ? '#fee2e2' : '#f3f4f6';
      const tc = idx === 0 ? '#065f46' : idx === 1 ? '#92400e' : idx === 2 ? '#991b1b' : '#6b7280';
      return `<tr><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;font-size:12px">${item.label}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;font-size:11px;color:#6b7280">${item.category || item.cat || ''}</td><td style="padding:6px 10px;border-bottom:1px solid #f3f4f6;text-align:center"><span style="background:${bg};color:${tc};padding:3px 8px;border-radius:9999px;font-size:10px;font-weight:700">${e} ${label}</span></td></tr>`;
    }).join('');
    const sig = cl.firma || cl.signature;
    const foto = cl.finalPhoto || cl.foto || cl.photo;
    const notas = cl.notas || cl.notes;
    const w = window.open('', '_blank', 'width=820,height=960');
    w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Chequeo - ${v?.code} - ${cl.date}</title><style>body{font-family:Arial,sans-serif;padding:20px;color:#1c1917;font-size:13px}@media print{.no-print{display:none}}h1{font-size:18px;margin:0;color:#047857}.hdr{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #10b981;padding-bottom:12px;margin-bottom:16px}.info{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:10px;margin-bottom:14px}.info label{font-size:10px;text-transform:uppercase;color:#6b7280;display:block;font-weight:700}table{width:100%;border-collapse:collapse;border:1px solid #e5e7eb;margin-bottom:14px}th{background:#f9fafb;padding:6px 10px;font-size:10px;text-transform:uppercase;color:#6b7280;text-align:left;border-bottom:1px solid #e5e7eb}.sf{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:14px}.sf-box{border:1px solid #e5e7eb;border-radius:8px;padding:10px}.sf-title{font-size:10px;text-transform:uppercase;color:#6b7280;font-weight:700;margin-bottom:6px}.print-btn{background:#047857;color:white;border:none;padding:8px 18px;border-radius:6px;cursor:pointer;font-weight:700;margin-bottom:16px;font-size:13px}.footer{margin-top:16px;border-top:1px solid #e5e7eb;padding-top:8px;font-size:10px;color:#9ca3af;display:flex;justify-content:space-between}</style></head><body><button class="no-print print-btn" onclick="window.print()">🖨️ Guardar como PDF / Imprimir</button><div class="hdr"><div><h1>Transporte Emporium</h1><div style="font-weight:700;margin-top:4px">Chequeo Pre-Viaje</div><div style="color:#6b7280">${v?.code || '—'} · ${v?.plate || '—'}</div></div><div style="text-align:right"><div style="font-size:20px;font-weight:700">${cl.date}</div><div style="margin:4px 0">${cl.time || ''}</div>${statusBadge}</div></div><div class="info"><div><label>Chofer</label><strong>${d?.name || '—'}</strong></div><div><label>Unidad</label><strong>${v?.code || '—'}</strong></div><div><label>Placa</label><strong>${v?.plate || '—'}</strong></div><div><label>KM Odómetro</label><strong>${(cl.kmOdometer || 0).toLocaleString()}</strong></div></div><table><tr><th>Ítem</th><th>Categoría</th><th>Estado</th></tr>${rows}</table>${notas ? `<div style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:8px;padding:10px;margin-bottom:14px"><div style="font-size:10px;text-transform:uppercase;color:#6b7280;font-weight:700;margin-bottom:4px">Novedades reportadas</div><div>${notas}</div></div>` : ''}<div class="sf"><div class="sf-box"><div class="sf-title">Firma del chofer</div>${sig ? `<img src="${sig}" style="width:100%;max-height:90px;object-fit:contain;background:#ffffff;border:1px solid #e5e7eb;border-radius:6px">` : '<div style="height:70px;background:#f9fafb;border-radius:6px;display:flex;align-items:center;justify-content:center;color:#9ca3af;font-size:11px">Sin firma</div>'}</div><div class="sf-box"><div class="sf-title">Foto de respaldo</div>${foto ? `<img src="${foto}" style="width:100%;max-height:120px;object-fit:cover;border-radius:6px">` : '<div style="height:90px;background:#f9fafb;border-radius:6px;display:flex;align-items:center;justify-content:center;color:#9ca3af;font-size:11px">Sin foto</div>'}</div></div><div class="footer"><span>Transporte Emporium · Sistema de Control de Flota</span><span>Generado: ${new Date().toLocaleString('es-VE')}</span></div></body></html>`);
    w.document.close(); w.focus();
  };
  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div>
          <h2 className="text-xl font-black text-stone-900">Checklists del día</h2>
          <p className="text-sm text-stone-500">{filtered.length} chequeo(s) encontrado(s)</p>
        </div>
        <div className="flex gap-2 flex-wrap">
          <input type="date" value={filterDate} onChange={e => setFilterDate(e.target.value)}
            className="border border-stone-200 rounded-lg px-3 py-1.5 text-sm font-mono bg-white text-stone-900 outline-none focus:border-emerald-500" />
          <select value={filterVehicle} onChange={e => setFilterVehicle(e.target.value)}
            className="border border-stone-200 rounded-lg px-3 py-1.5 text-sm bg-white text-stone-900 outline-none focus:border-emerald-500">
            <option value="all">Todas las unidades</option>
            {vehicles.map(v => <option key={v.id} value={v.id}>{v.code}</option>)}
          </select>
        </div>
      </div>
      <div className="flex items-center gap-2 flex-wrap bg-rose-50 border border-rose-200 rounded-xl p-3 mt-2">
          <input type="date" value={deleteUntil} onChange={e => setDeleteUntil(e.target.value)}
            className="border border-rose-300 rounded-lg px-3 py-1.5 text-sm font-mono bg-white text-stone-900 outline-none focus:border-rose-500" />
          <select value={deleteVehicle} onChange={e => setDeleteVehicle(e.target.value)}
            className="border border-rose-300 rounded-lg px-3 py-1.5 text-sm bg-white text-stone-900 outline-none focus:border-rose-500">
            <option value="all">🚛 Todas las unidades</option>
            {vehicles.map(v => <option key={v.id} value={v.id}>{v.code} · {v.plate}</option>)}
          </select>
          <button onClick={handleDeleteOld}
            className="px-4 py-1.5 rounded-lg bg-rose-600 hover:bg-rose-700 text-white text-sm font-bold flex items-center gap-1">
            🗑️ Borrar anteriores
          </button>
        </div>
      {filtered.length === 0 ? (
        <div className="bg-white rounded-2xl border border-stone-200 p-12 text-center text-stone-400">
          <CheckCircle2 className="w-12 h-12 mx-auto mb-3 opacity-30" />
          <div className="font-bold">Sin checklists para esta fecha</div>
          <div className="text-sm mt-1">Los choferes deben completar el chequeo antes de cada viaje</div>
        </div>
      ) : (
        <div className="space-y-2">
          {filtered.map(cl => {
            const v = vehicles.find(x => x.id === cl.vehicleId);
            const d = drivers.find(x => x.id === cl.driverId);
            const crits = cl.criticalCount || 0;
            const warns = cl.warningCount || 0;
            const sig = cl.firma || cl.signature;
            const foto = cl.finalPhoto || cl.foto || cl.photo;
            return (
              <div key={cl.id} className="bg-white rounded-2xl border border-stone-200 shadow-sm p-4 flex items-center justify-between flex-wrap gap-3">
                <div className="flex items-center gap-3 flex-1 min-w-0">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shrink-0 ${crits > 0 ? 'bg-rose-100' : warns > 0 ? 'bg-amber-100' : 'bg-emerald-100'}`}>
                    {crits > 0 ? '🔴' : warns > 0 ? '⚠️' : '✅'}
                  </div>
                  <div className="min-w-0">
                    <div className="font-bold text-stone-900">{v?.code} · {d?.shortName || d?.name}</div>
                    <div className="text-xs text-stone-500 font-mono">{cl.date} {cl.time} · {Object.keys(cl.items || {}).length}/14 ítems</div>
                    {crits > 0 && <div className="text-xs text-rose-700 font-bold">{crits} crítico(s)</div>}
                    {warns > 0 && !crits && <div className="text-xs text-amber-700 font-bold">{warns} para revisar</div>}
                  </div>
                </div>
                <div className="flex gap-2 items-center flex-wrap">
                  {sig && <span className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-1 rounded-full font-bold">✍️ Firma</span>}
                  {foto && <span className="text-[10px] bg-blue-100 text-blue-700 px-2 py-1 rounded-full font-bold">📸 Foto</span>}
                  <button onClick={() => openPDF(cl)}
                    className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-1.5 shadow-md transition active:scale-[0.98]">
                    <FileText className="w-4 h-4" /> Ver PDF
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
      <div className="bg-blue-50 border border-blue-200 rounded-xl p-3 text-xs text-blue-900">
        💡 <b>Cómo guardar PDF:</b> Click en "Ver PDF" → nueva ventana → "🖨️ Guardar como PDF".
      </div>
    </div>
  );
}

